class CombinationIterator {

    private String characters;
    private int combinationLength;
    private int index;
    private int[] current;
    private int n;

    public CombinationIterator(String characters, int combinationLength) {
        this.characters = characters;
        this.combinationLength = combinationLength;
        this.n = characters.length();
        this.index = 0;
        this.current = new int[combinationLength];
        for (int i = 0; i < combinationLength; i++) {
            current[i] = i;
        }
    }

    public String next() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < combinationLength; i++) {
            sb.append(characters.charAt(current[i]));
        }
        for (int i = combinationLength - 1; i >= 0; i--) {
            if (current[i] < n - combinationLength + i) {
                current[i]++;
                for (int j = i + 1; j < combinationLength; j++) {
                    current[j] = current[j - 1] + 1;
                }
                break;
            }
        }
        return sb.toString();
    }

    public boolean hasNext() {
        for (int i = 0; i < combinationLength; i++) {
            if (current[i] < n - combinationLength + i) {
                return true;
            }
        }
        return false;
    }
}
